import numpy as np
from itertools import product as iterproduct


def my_einsum(subscripts, *operands):
    """Evaluate a subset of Einstein-summation expressions from scratch."""
    if "->" not in subscripts:
        raise ValueError("subscripts must contain '->'")
    lhs, out_spec = subscripts.split("->")
    in_specs = lhs.split(",")
    if len(in_specs) != len(operands):
        raise ValueError(
            f"Got {len(in_specs)} input specs but {len(operands)} operands"
        )

    arrays = [np.asarray(op, dtype=float) for op in operands]
    for spec, arr in zip(in_specs, arrays):
        if len(spec) != arr.ndim:
            raise ValueError(
                f"Spec '{spec}' has {len(spec)} indices but array has "
                f"{arr.ndim} dims"
            )

    sizes = {}
    for spec, arr in zip(in_specs, arrays):
        for letter, dim in zip(spec, arr.shape):
            if letter in sizes and sizes[letter] != dim:
                raise ValueError(
                    f"Inconsistent size for index '{letter}': "
                    f"{sizes[letter]} vs {dim}"
                )
            sizes[letter] = dim

    all_indices = sorted(sizes.keys())
    out_data = {}
    for combo in iterproduct(*(range(sizes[i]) for i in all_indices)):
        assignment = dict(zip(all_indices, combo))
        term = 1.0
        for spec, arr in zip(in_specs, arrays):
            term *= arr[tuple(assignment[l] for l in spec)]
        out_key = tuple(assignment[l] for l in out_spec)
        out_data[out_key] = out_data.get(out_key, 0.0) + term

    out_shape = tuple(sizes[l] for l in out_spec)
    if out_shape == ():
        return np.float64(out_data.get((), 0.0))
    result = np.zeros(out_shape, dtype=float)
    for key, val in out_data.items():
        result[key] = val
    return result
